<?php
namespace Yellowstep\ElementorEditor\Abilities;
use Yellowstep\ElementorEditor\Core;
if (!defined('ABSPATH')) { exit; }
final class Registrar {
    private static bool $registered=false;
    public static function register(): void { if(self::$registered||!function_exists('wp_register_ability')){return;} self::$registered=true; self::ability('list-pages','List Elementor-built pages.',[Executor::class,'listPages'],true); self::ability('list-templates','List Elementor templates.',[Executor::class,'listTemplates'],true); self::ability('get-semantic-map','Get a semantic map of an Elementor page.',[Executor::class,'getSemanticMap'],true,['post_id'=>['type'=>'integer','required'=>true]]); self::ability('duplicate-page','Duplicate an Elementor page as a draft or chosen status.',[Executor::class,'duplicatePage'],false,['post_id'=>['type'=>'integer','required'=>true],'title'=>['type'=>'string','required'=>true],'slug'=>['type'=>'string'],'status'=>['type'=>'string','default'=>'draft']]); self::ability('create-service-page','Create a service page by duplicating an existing Elementor page.',[Executor::class,'createServicePage'],false,['source_id'=>['type'=>'integer','required'=>true],'title'=>['type'=>'string','required'=>true],'slug'=>['type'=>'string'],'status'=>['type'=>'string','default'=>'draft'],'seo_title'=>['type'=>'string'],'meta_description'=>['type'=>'string'],'focus_keyphrase'=>['type'=>'string']]); self::ability('update-hero','Update the hero heading and/or intro for a page.',[Executor::class,'updateHero'],false,['post_id'=>['type'=>'integer','required'=>true],'heading'=>['type'=>'string'],'intro'=>['type'=>'string']]); self::ability('update-card','Update a framework/icon card by index.',[Executor::class,'updateCard'],false,['post_id'=>['type'=>'integer','required'=>true],'index'=>['type'=>'integer','required'=>true],'title'=>['type'=>'string'],'description'=>['type'=>'string']]); self::ability('update-faq','Update an FAQ question and/or answer by index.',[Executor::class,'updateFaq'],false,['post_id'=>['type'=>'integer','required'=>true],'index'=>['type'=>'integer','required'=>true],'question'=>['type'=>'string'],'answer'=>['type'=>'string']]); self::ability('replace-text','Replace exact text across Elementor settings on a page.',[Executor::class,'replaceText'],false,['post_id'=>['type'=>'integer','required'=>true],'old_text'=>['type'=>'string','required'=>true],'new_text'=>['type'=>'string','required'=>true]]); self::ability('update-yoast','Update Yoast SEO metadata for a page.',[Executor::class,'updateYoast'],false,['post_id'=>['type'=>'integer','required'=>true],'seo_title'=>['type'=>'string'],'meta_description'=>['type'=>'string'],'focus_keyphrase'=>['type'=>'string']]); self::ability('list-snapshots','List snapshots available for rollback.',[Executor::class,'snapshots'],true,['post_id'=>['type'=>'integer','required'=>true]]); self::ability('rollback','Roll back a page to the latest or specified snapshot.',[Executor::class,'rollback'],false,['post_id'=>['type'=>'integer','required'=>true],'index'=>['type'=>'integer']]); self::ability('regenerate-css','Regenerate/clear Elementor CSS cache.',[Executor::class,'regenerateCss'],false,['post_id'=>['type'=>'integer']]); }
    private static function ability(string $slug,string $description,callable $callback,bool $readonly=false,array $properties=[]): void { $inputSchema=['type'=>'object','properties'=>self::normaliseProperties($properties),'additionalProperties'=>false]; $required=[]; foreach($properties as $name=>$schema){ if(!empty($schema['required'])){$required[]=$name;} } if($required){$inputSchema['required']=$required;} $args=['label'=>ucwords(str_replace('-',' ',$slug)),'description'=>$description,'category'=>Core::ABILITY_CATEGORY,'input_schema'=>$inputSchema,'output_schema'=>['type'=>'object','additionalProperties'=>true],'execute_callback'=>$callback,'permission_callback'=>[Core::class,'canEditPages'],'annotations'=>['readonly'=>$readonly,'idempotent'=>$readonly,'destructive'=>false]]; wp_register_ability('yellowstep/'.$slug,$args); }
    private static function normaliseProperties(array $properties): array { $normalised=[]; foreach($properties as $name=>$schema){ unset($schema['required']); $normalised[$name]=$schema; } return $normalised; }
}
